INSERT INTO `beer_entry_extra_field` VALUES (1,1,'specialIngredients','?????????','????'),(2,2,'specialIngredients','增味原料或特殊工艺','none'),(3,63,'specialIngredients','增味原料或特殊工艺','爆炸发酵'),(4,41001,'specialIngredients','增味原料或特殊工艺','测试酒款：清爽米香、轻麦芽、低苦度。'),(5,41002,'specialIngredients','增味原料或特殊工艺','测试酒款：淡麦芽、草本酒花、干净发酵。'),(6,41003,'specialIngredients','增味原料或特殊工艺','测试酒款：面包麦香、柔和甜感、清亮酒体。'),(7,41004,'specialIngredients','增味原料或特殊工艺','测试酒款：低酯香、轻麦芽、适饮性高。'),(8,41005,'specialIngredients','增味原料或特殊工艺','测试酒款：饼干麦芽、细腻酒花、余味干爽。'),(9,41006,'specialIngredients','增味原料或特殊工艺','测试酒款：烘烤麦芽、轻焦糖、低酯香。'),(10,41007,'specialIngredients','增味原料或特殊工艺','测试酒款：可可感、面包皮、圆润酒体。'),(11,41008,'specialIngredients','增味原料或特殊工艺','测试酒款：轻烘烤、深色麦芽、清爽尾韵。'),(12,41009,'specialIngredients','增味原料或特殊工艺','测试酒款：坚果、焦糖、烘烤麦芽。'),(13,41010,'specialIngredients','增味原料或特殊工艺','测试酒款：轻巧咖啡、焦糖、干净发酵。'),(14,41011,'specialIngredients','增味原料或特殊工艺','马达加斯加香草奶油'),(15,41013,'specialIngredients','增味原料或特殊工艺','焦糖与香草缠绵'),(16,41014,'specialIngredients','增味原料或特殊工艺','低温长时发酵'),(17,41015,'specialIngredients','增味原料或特殊工艺','软水糖化与草本型酒花'),(18,41016,'specialIngredients','增味原料或特殊工艺','深色麦芽与低温熟成'),(21,41020,'specialIngredients','增味原料','芫荽籽和海盐'),(22,41021,'specialIngredients','增味原料','茶水'),(23,41022,'specialIngredients','增味原料','112'),(24,41023,'specialIngredients','增味原料','桶陈'),(25,41024,'specialIngredients','增味原料','烘烤麦芽'),(26,41025,'specialIngredients','增味原料','茶叶'),(27,41026,'specialIngredients','增味原料','西瓜'),(28,42615,'specialIngredients','增味原料或特殊工艺','烟熏胡桃木'),(29,42616,'specialIngredients','增味原料或特殊工艺','1'),(30,42617,'specialIngredients','增味原料或特殊工艺','烟熏工艺'),(31,42670,'specialIngredients','增味原料或特殊工艺','蜜桃乌龙茶'),(32,42737,'specialIngredients','增味原料或特殊工艺','啤酒花'),(33,42738,'specialIngredients','增味原料或特殊工艺','黑曜石'),(34,43382,'specialIngredients','增味原料或特殊工艺','11111'),(36,43383,'specialIngredients','增味原料或特殊工艺','111'),(37,43384,'specialIngredients','增味原料或特殊工艺','1111'),(38,43507,'specialIngredients','增味原料或特殊工艺','草莓过桶工艺'),(39,43509,'specialIngredients','增味原料或特殊工艺','面包、坚果'),(40,43510,'specialIngredients','增味原料或特殊工艺','皮尔森基底麦芽搭配烘烤黑麦芽'),(41,43511,'specialIngredients','增味原料或特殊工艺','基底浅色拉格，煮沸末期添加增味原料，低温冷发酵柔和融合果香/草本风味，后期冷浸锁鲜提香。'),(42,43512,'specialIngredients','增味原料或特殊工艺','深拉格麦芽基底，依托低温长时间窖藏发酵，烘烤麦芽自带焦糖、可可基调。于煮沸末期及冷浸阶段分次投入增味原料，柔和叠加风味，平衡焦香厚重感，香气干净不突兀。'),(43,43513,'specialIngredients','增味原料或特殊工艺','爱的配方'),(44,43514,'specialIngredients','增味原料或特殊工艺','发大水发'),(45,43515,'specialIngredients','增味原料或特殊工艺','金酒'),(46,43520,'specialIngredients','增味原料或特殊工艺','皮尔森浅色拉格，煮沸、冷浸双阶段添加增味原料，低温慢酿融合风味。'),(47,43823,'specialIngredients','增味原料或特殊工艺','三倍干投酒花'),(52,44008,'specialIngredients','增味原料或特殊工艺','啤酒花'),(53,44009,'specialIngredients','增味原料或特殊工艺','酒花'),(54,44010,'specialIngredients','增味原料或特殊工艺','茶叶'),(55,44011,'specialIngredients','增味原料或特殊工艺','烟熏工艺'),(58,44455,'specialIngredients','增味原料或特殊工艺','122'),(59,44456,'specialIngredients','增味原料或特殊工艺','23');
/*!40000 ALTER TABLE `beer_entry_extra_field` ENABLE KEYS */;
