INSERT INTO `competition` VALUES (1,'BC-2026','2026 大湾区精酿啤酒大赛','2026-08-18','2026-06-01 10:00:00','2026-07-31 23:59:59','REGISTRATION_OPEN','AWARD',299.00,NULL,NULL,'这场赛事面向精酿厂牌开放报名，请按赛事要求提交适合的酒款。',NULL,'BJCP_2021_CN','BOTH',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'PAYMENT_CONFIRMED',1,'2026-06-02 21:39:35','2026-06-09 19:37:49'),(2,'BC-20260820-WSW1C','2026 新建精酿啤酒赛','2026-08-20','2026-06-01 10:00:00','2026-07-30 18:00:00','ARCHIVED','AWARD',199.00,NULL,NULL,'这场赛事面向精酿厂牌开放报名，请按赛事要求提交适合的酒款。',NULL,'BJCP_2021_CN','BOTH',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'PAYMENT_CONFIRMED',0,'2026-06-03 09:42:07','2026-06-09 19:37:49'),(3,'BC-20260820-7757C','2026 新建精酿啤酒赛2','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','REGISTRATION_CLOSED','AWARD',199.00,159.00,'2026-06-30 18:00:00','这场赛事面向精酿厂牌开放报名，请按赛事要求提交适合的酒款。','https://mp.weixin.qq.com/s/iGxSnomHIXvdOyMO9xgd2Q','BJCP_2021_CN','BOTH',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'PAYMENT_CONFIRMED',0,'2026-06-03 20:03:44','2026-06-09 21:12:16'),(4,'BC-20260820-3P3JZ','2026 新建精酿啤酒赛3','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','PUBLISHED','AWARD',199.00,NULL,NULL,'这场赛事面向精酿厂牌开放报名，请按赛事要求提交适合的酒款。',NULL,'BJCP_2021_CN','EXPRESS','2026-08-10 10:00:00','2026-08-15 18:00:00','每款 6 瓶，单瓶容量建议不低于 330ml。','赛事收样组','124065660459','827 Chuo-dori, Matsue, Shimane 690-0001, Japan','请做好防震、防漏和外箱加固；每款酒瓶身至少贴 1 张现场标签，整箱寄送时建议外箱再贴 1 张。','PAYMENT_CONFIRMED',0,'2026-06-04 20:47:28','2026-06-09 19:37:49'),(5,'BC-20260820-5I93K','2026 新建精酿啤酒赛','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','ARCHIVED','AWARD',199.00,NULL,NULL,'这场赛事面向精酿厂牌开放报名，请按赛事要求提交适合的酒款。',NULL,'BJCP_2021_CN','BOTH','2026-08-10 10:00:00','2026-08-15 18:00:00','每款 6 瓶，单瓶容量建议不低于 330ml。','赛事收样组','19230495967','广东省深圳市南山区海湾路8号蛇口价值工厂','请做好防震、防漏和外箱加固；每款酒瓶身至少贴 1 张现场标签，整箱寄送时建议外箱再贴 1 张。','PAYMENT_CONFIRMED',0,'2026-06-06 13:34:00','2026-06-09 19:37:49'),(6,'BC-20260820-W2KE0','2026 新建精酿啤酒赛4','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','ARCHIVED','AWARD',199.00,159.00,'2026-06-30 18:00:00','这场赛事面向精酿厂牌开放报名，请按赛事要求提交适合的酒款。',NULL,'BJCP_2021_CN','EXPRESS','2026-08-10 10:00:00','2026-08-15 18:00:00','每款 6 瓶，单瓶容量建议不低于 330ml。','赛事收样组','1235467865465','广东省深圳市南山区海湾路8号蛇口价值工厂','请做好防震、防漏和外箱加固；每款酒瓶身至少贴 1 张现场标签，整箱寄送时建议外箱再贴 1 张。','PAYMENT_CONFIRMED',0,'2026-06-06 14:03:45','2026-06-09 19:44:36'),(7,'BC-20260820-K2Q8A','首届中国拉格专题大赛','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','PUBLISHED','AWARD',199.00,99.00,'2026-06-30 18:00:00','首届中国拉格专题大赛，是国内首个专注拉格啤酒的专项专业赛事。赛事面向商酿品牌、精酿工坊、独立酿酒师及高校研发团队，参赛品类覆盖经典皮尔森、淡色拉格、黑拉格、特色风味拉格等。大赛集结国家级评酒委员、专业裁判与酿造专家，依照国际标准开展品鉴评审。赛事以赛促交流、以赛提品质，挖掘酿造人才，探索本土特色风味，助力国内拉格酿造工艺升级与行业高质量发展。','https://mp.weixin.qq.com/s/iGxSnomHIXvdOyMO9xgd2Q','BJCP_2021_CN','EXPRESS','2026-08-10 10:00:00','2026-08-15 18:00:00','每款 6 瓶，单瓶容量建议不低于 330ml','赛事收样组','12049995939','浙江省宁波市鄞州区首南街道锦悦花苑 3 栋 2 单元 501 室','请做好防震、防漏和外箱加固；每款酒瓶身至少贴 1 张现场标签，整箱寄送时建议外箱再贴 1 张','PAYMENT_CONFIRMED',0,'2026-06-09 21:47:16','2026-06-09 21:47:16'),(481,'BC-20260820-UUH4X','中国第二届精酿拉格大赛','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','JUDGING','AWARD',199.00,0.01,'2026-06-30 18:00:00','延续“纯粹匠心，致敬经典”的宗旨，旨在挖掘本土拉格酿造技艺的无限潜力。本届大赛面向全国精酿厂牌、家酿爱好者及职业酿酒师开放，设置德式清亮、波西米亚风格、深色拉格及创新实验拉格四大竞赛组别。特邀国际BJCP认证评委与国内资深酿酒专家组成评审团，从原料纯净度、发酵工艺与风味平衡度进行严苛打分。','https://mp.weixin.qq.com/s/iGxSnomHIXvdOyMO9xgd2Q','BJCP_2021_CN','BOTH','2026-08-10 10:00:00','2026-08-15 18:00:00','每款 6 瓶，单瓶容量建议不低于 330ml','赛事收样组','12060003020','中国北京市朝阳区酒仙桥路188号精酿创新园区B座3层','请做好防震、防漏和外箱加固；每款酒瓶身至少贴 1 张现场标签，整箱寄送时建议外箱再贴 1 张。','PAYMENT_CONFIRMED',0,'2026-06-17 18:20:55','2026-06-17 18:20:55'),(702,'BC-20260820-ARCHP','布鲁塞尔风格对齐会','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','PUBLISHED','FEEDBACK_ONLY',199.00,0.10,'2026-06-30 18:00:00','面向精酿厂牌的综合赛事，适合提交稳定量产款和年度新品','https://mp.weixin.qq.com/s/iGxSnomHIXvdOyMO9xgd2Q','BJCP_2021_CN','EXPRESS','2026-08-10 10:00:00','2026-08-15 18:00:00','每款 6 瓶，单瓶容量不低于 330ml','赛事收样组','1','1','请做好防震、防漏和外箱加固；每款酒瓶身至少贴 1 张现场标签，整箱寄送时外箱必须再贴 1 张','PAYMENT_CONFIRMED',0,'2026-06-25 15:32:25','2026-06-25 15:32:25'),(739,'BC-20260820-OODAR','啤酒事务局风格对齐会：布鲁塞尔','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','REGISTRATION_OPEN','FEEDBACK_ONLY',199.00,0.01,'2026-06-30 18:00:00','“风格对齐会”是啤酒事务局为中国酒厂参加国际啤酒比赛量身打造的赛前模拟评审与投报诊断项目。首期活动聚焦2026年布鲁塞尔啤酒挑战赛（BBC）——全球含金量最高的国际啤酒赛事之一。我们将邀请专业啤酒裁判，严格依照BBC官方组别和评分表，对参赛酒款进行盲品评审。每款酒将获得完整模拟评分、感官反馈、原组别适配判断及推荐投报组别。我们不做排名、不颁奖，只做一件事：帮助中国好酒在正式投送前，先找到最适合自己的赛道','https://brusselsbeerchallenge.com','BBC_2026_CN','EXPRESS','2026-08-10 10:00:00','2026-08-15 18:00:00','每款酒寄送2瓶/罐；3升或5升桶装1桶即可','赛事收样组',NULL,'上海市静安区胶州路709号','如需打酒器，请一同寄送','PAYMENT_CONFIRMED',0,'2026-06-26 11:16:13','2026-06-26 11:16:13'),(740,'BC-20260815-TMEKL','首届中国拉格大赛','2026-08-15','2026-05-25 10:00:00','2026-08-11 00:00:00','RESULT_CONFIRMING','AWARD',199.00,0.01,'2026-08-01 00:00:00','我们希望把中国酒厂里真正优秀的拉格作品筛选出来，让更多消费者意识到：优秀的拉格啤酒，绝非风味的缺失，而是有意识的返璞归真，华丽而克制的风格表达。','https://mp.weixin.qq.com/s/iGxSnomHIXvdOyMO9xgd2Q','BJCP_2021_CN','EXPRESS','2026-08-01 00:00:00','2026-08-12 18:00:00','330 - 499 毫升规格至少4瓶/罐；500 毫升或以上规格至少3瓶/罐；如3升或5升桶，1桶即可（如需打酒器，请一同寄送）','骆新源','18149705349','上海市闵行区益梅路91号5号楼1楼力波1987精酿','张贴之前，请移除参赛酒款原本的酒标。建议采用激光打印，并在贴后使用透明塑料胶带覆盖，以增加防水性。','LOGIN_REQUIRED',0,'2026-07-01 15:05:40','2026-07-01 15:05:40'),(809,'BC-20260820-HKLNR','中国第三届精酿拉格大赛','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','PUBLISHED','AWARD',199.00,0.01,'2026-07-12 18:00:00','我们希望把中国酒厂里真正优秀的拉格作品筛选出来，让更多消费者意识到：优秀的拉格啤酒，绝非风味的缺失，而是有意识的返璞归真，华丽而克制的风格表达','https://mp.weixin.qq.com/s/iGxSnomHIXvdOyMO9xgd2Q','BJCP_2021_CN','EXPRESS','2026-08-10 10:00:00','2026-08-15 18:00:00','每款 6 瓶，单瓶容量不低于 330ml','赛事收样组','12406006043','浙江省上海市浦东新区001号','请做好防震、防漏和外箱加固；每款酒瓶身至少贴 1 张现场标签，整箱寄送时外箱必须再贴 1 张','PAYMENT_CONFIRMED',0,'2026-07-03 12:20:25','2026-07-03 12:20:25'),(1010,'BC-20260820-XIV9L','中国第四届拉格大赛','2026-08-20','2026-06-10 10:00:00','2026-07-30 18:00:00','JUDGING','AWARD',199.00,0.01,'2026-06-30 18:00:00','面向精酿厂牌的综合赛事，适合提交稳定量产款和年度新品','https://mp.weixin.qq.com/s/iGxSnomHIXvdOyMO9xgd2Q','BJCP_2021_FULL_CN','EXPRESS','2026-08-10 10:00:00','2026-08-15 18:00:00','每款 6 瓶，单瓶容量不低于 330ml','赛事收样组','1230500607','浙江省上海市浦东888号','请做好防震、防漏和外箱加固；每款酒瓶身至少贴 1 张现场标签，整箱寄送时外箱必须再贴 1 张','PAYMENT_CONFIRMED',0,'2026-07-05 00:20:41','2026-07-05 00:20:41');
