  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_competition_style_name` (`competition_id`,`name`)
) ENGINE=InnoDB AUTO_INCREMENT=2300 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='比赛可选基础风格配置表';
